args.ReplacementContent:
"                      // Questions status parsing
                      let questionsStatus = 'NONE';
                      let questionsResponses: any = null;
                      if (parsedData.questions) {
                        const qVal = parsedData.questions;
                        if (qVal === 'PENDING') {
                          questionsStatus = 'PENDING';
                        } else if (qVal.startsWith('COMPLETED===')) {
                          questionsStatus = 'COMPLETED';
                          try {
                            const jsonStr = qVal.replace('COMPLETED===', '').trim();
                            questionsResponses = JSON.parse(jsonStr);
                          } catch (err) {
                            console.error('Erro ao fazer parse do JSON de respostas:', err);
                          }
                        }
                      }

                      return {
                        ...applicant,
                        fullApp,
                        matchScore,
                        normalizedStatus,
                        discStatus,
                        notes: parsedData.notes,
                        questionsStatus,
                        questionsResponses,
                        D, I, S, C
                      };
                    });"

